import os
import uuid
from azure.functions import (
    HttpRequest,
    HttpResponseDefault,
    Context,
    ManagedIdentityClient,
)
from azure.cosmosdb.table.tableservice import TableService, Entity
from azure.storage.blob import BlobServiceClient
from datetime import datetime
import json
import logging
import base64

AZURE_STORAGE_CONNECTION_STRING = os.environ['AZURE_STORAGE_CONNECTION_STRING']
COSMOS_DB_ACCOUNT_NAME = os.environ['COSMOS_DB_ACCOUNT_NAME']
COSMOS_DB_ACCOUNT_KEY = os.environ['COSMOS_DB_ACCOUNT_KEY']
EVENT_GRID_ENDPOINT = os.environ['EVENT_GRID_ENDPOINT']

managed_identity_client = ManagedIdentityClient()
credentials = managed_identity_client.get_token('https://storage.azure.com/.default')
logging.info(credentials)

def main(req: HttpRequest, context: Context) -> HttpResponseDefault:
    if 'x-ms-blob-type' in req.headers and req.headers['x-ms-blob-type'] == 'BlockBlob':
        logging.info("Processing Block Blob")
        process_blob_blob(context)
    elif 'x-ms-blob-type' in req.headers and req.headers['x-ms-blob-type'] == 'PageBlob':
        logging.info("Processing Page Blob")
        process_blob_pageblob(context)
    else:
        return HttpResponseDefault('{"error": "Invalid blob type"}', 400)

def process_blob_blob(context):
    try:
        table_service = TableService(COSMOS_DB_ACCOUNT_NAME, COSMOS_DB_ACCOUNT_KEY)
        
        logging.info("Getting file from storage")
        container_name = req.headers['x-ms-container']
        blob_name = req.headers['x-ms-blob-name']
        client = BlobServiceClient.from_connection_string(AZURE_STORAGE_CONNECTION_STRING)
        blob_client = client.get_blob_client(container=container_name, blob=blob_name)
        
        logging.info("Downloading file from storage")
        data = blob_client.download_blob().content_as_text()
        
        result_entity = Entity(partition_key=str(uuid.uuid4()), row_key=str(datetime.now()))
        result_entity['data'] = data
        table_service.insert_or_replace_entity('my_table', result_entity)
        
        logging.info("Inserting entity into Cosmos DB")
        
    except Exception as e:
        logging.error(f"Error processing file: {str(e)}")

